using VisionaryCoder.Generators.Domain;
using Xunit;

namespace vc.Generators.Tests; public sealed class StrongIdGeneratorTests { private static ImmutableArray<SyntaxTree> GetCompilation(string source, string attributeSource) =>
    [CSharpSyntaxTree.ParseText(text: attributeSource), CSharpSyntaxTree.ParseText(text: source)]; private static Compilation CreateCompilation(ImmutableArray<SyntaxTree> trees) { var references = AppDomain.CurrentDomain.GetAssemblies().Where(predicate: a => !a.IsDynamic && a.Location.Length > 0).Select(selector: a => MetadataReference.CreateFromFile(path: a.Location)).Distinct().ToArray(); return CSharpCompilation.Create(assemblyName: "GeneratorTest").AddReferences(references: references).AddSyntaxTrees(trees: trees); } private static (Compilation, IEnumerable<string>) RunGenerator(string source, string attributeSource = "") { var defaultAttribute = "namespace Vc.Generators.Abstractions.Domain; [AttributeUsage(AttributeTargets.Struct)] public sealed class VcStrongIdAttribute : Attribute {}"; var attr = string.IsNullOrEmpty(value: attributeSource) ? defaultAttribute : attributeSource; var trees = GetCompilation(source: source, attributeSource: attr); var compilation = CreateCompilation(trees: trees); var generator = new StrongIdGenerator(); var driver = CSharpGeneratorDriver.Create(incrementalGenerators: generator); driver.RunGeneratorsAndUpdateCompilation(compilation: compilation, outputCompilation: out var outputCompilation, diagnostics: out _); var sources = outputCompilation.SyntaxTrees.Skip(count: compilation.SyntaxTrees.Count()).Select(selector: st => st.GetText().ToString()).ToList(); return (outputCompilation, sources); } [Fact] public void GeneratorExecutes() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.True(condition: true); } [Fact] public void ProducesOutput() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.NotEmpty(collection: s); } [Fact] public void ContainsValueProperty() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "Value", actualString: s.First()); } [Fact] public void ContainsEquality() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "Equals", actualString: s.First()); } [Fact] public void ContainsGetHashCode() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "GetHashCode", actualString: s.First()); } [Fact] public void ContainsComparison() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "==", actualString: s.First()); } [Fact] public void ContainsAutoGenHeader() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "auto-generated", actualString: s.First()); } [Fact] public void ContainsNullableDirective() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains(expectedSubstring: "#nullable", actualString: s.First()); } [Fact] public void IsDeterministic() { var (_, s1) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); var (_, s2) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Equal(expected: s1.First(), actual: s2.First()); } [Fact] public void PreservesNamespace() { var (_, s) = RunGenerator(source: "using Vc.Generators.Abstractions.Domain; namespace Domain.Ids; [VcStrongId] public partial struct OrderId {}"); Assert.Contains(expectedSubstring: "namespace Domain.Ids", actualString: s.First()); } }
